import{_ as d,r,o as c,c as p,a as e,b as t,t as i,d as o,w as l,e as h}from"./app-d223f2a5.js";const g={},y={id:"frontmatter-title-관련",tabindex:"-1"},w=e("a",{class:"header-anchor",href:"#frontmatter-title-관련","aria-hidden":"true"},"#",-1),m={class:"table-of-contents"},f=h('<hr><h2 id="project-5-part-three" tabindex="-1"><a class="header-anchor" href="#project-5-part-three" aria-hidden="true">#</a> Project 5, part three</h2><p>I hope that today you inched a little closer to understanding closures, and that you’re starting to see that they are really just a very special kind of function. Sure they have weird syntax, and yes the capturing thing makes them behave in all sorts of interesting ways, but ultimately they are just anonymous functions that you pass around as if they were data.</p><p>If you’re still not sure about closures, it’s OK: we’ll be using them again and again, and sooner or later they’ll click. You’d do well to remember the words of Patrick McKenzie: “every great developer you know got there by solving problems they were unqualified to solve until they actually did it.”</p><p>Anyway, you have another project under your belt, and I hope you feel happy with everything you learned. Of course, now it’s time to solidify your knowledge with a test and some fresh challenges – you <em>need</em> to go beyond just following along with me, otherwise you’ll have a hard time remembering anything in the long term.</p><p><strong>Today you should work through the wrap up chapter for project 5, complete its review, then work through all three of its challenges. As you’ll see, there is also a bonus challenge today – you need to be a bug detective!</strong></p><h3 id="wrap-up" tabindex="-1"><a class="header-anchor" href="#wrap-up" aria-hidden="true">#</a> Wrap up</h3>',7),b={class:"hint-container details"},_=e("summary",null,"Wrap up",-1),v={href:"https://hackingwithswift.com/read/5/7/wrap-up",target:"_blank",rel:"noopener noreferrer"},k=e("p",null,"You've made it this far, so your Swift learning really is starting to come together, and I hope this project has shown you that you can make some pretty advanced things with your knowledge.",-1),j=e("p",null,[t("In this project, you learned a little bit more about "),e("code",null,"UITableView"),t(": how to reload their data and how to insert rows. You also learned how to add text fields to "),e("code",null,"UIAlertController"),t(" so that you can accept user input. But you also learned some serious core stuff: more about Swift strings, closures, "),e("code",null,"NSRange"),t(", and more. These are things you're going to use in dozens of projects over your Swift coding career, and things we'll be returning to again and again in this series.")],-1),I=e("h4",{id:"review-what-you-learned",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#review-what-you-learned","aria-hidden":"true"},"#"),t(" Review what you learned")],-1),x=e("p",null,"Anyone can sit through a tutorial, but it takes actual work to remember what was taught. It’s my job to make sure you take as much from these tutorials as possible, so I’ve prepared a short review to help you check your learning.",-1),S={href:"https://hackingwithswift.com/review/hws/project-5-word-scramble",target:"_blank",rel:"noopener noreferrer"},B=h(`<h4 id="challenge" tabindex="-1"><a class="header-anchor" href="#challenge" aria-hidden="true">#</a> Challenge</h4><p>One of the best ways to learn is to write your own code as often as possible, so here are three ways you should try extending this app to make sure you fully understand what’s going on:</p><ol><li>Disallow answers that are shorter than three letters or are just our start word. For the three-letter check, the easiest thing to do is put a check into <code>isReal()</code> that returns false if the word length is under three letters. For the second part, just compare the start word against their input word and return false if they are the same.</li><li>Refactor all the <code>else</code> statements we just added so that they call a new method called <code>showErrorMessage()</code>. This should accept an error message and a title, and do all the <code>UIAlertController</code> work from there.</li><li>Add a left bar button item that calls <code>startGame()</code>, so users can restart with a new word whenever they want to.</li></ol><p><strong>Bonus</strong>: Once you’ve done those three, there’s a really subtle bug in our game and I’d like you to try finding and fixing it.</p><p>To trigger the bug, look for a three-letter word in your starting word, and enter it with an uppercase letter. Once it appears in the table, try entering it again all lowercase – you’ll see it gets entered. Can you figure out what causes this and how to fix it?</p><h4 id="hints" tabindex="-1"><a class="header-anchor" href="#hints" aria-hidden="true">#</a> Hints</h4><p>It is <em>vital</em> to your learning that you try the challenges above yourself, and not just for a handful of minutes before you give up.</p><p>Every time you try something wrong, you learn that it’s wrong and you’ll remember that it’s wrong. By the time you find the <em>correct</em> solution, you’ll remember it much more thoroughly, while also remembering a lot of the wrong turns you took.</p><p>This is what I mean by “there is no learning without struggle”: if something comes easily to you, it can go just as easily. But when you have to really mentally fight for something, it will stick much longer.</p><p>But if you’ve already worked hard at the challenges above and are still struggling to implement them, I’m going to write some hints below that should guide you to the correct answer.</p><p><strong>If you ignore me and read these hints without having spent at least 30 minutes trying the challenges above, the only person you’re cheating is yourself.</strong></p><p>Still here? OK. If you’re stuck on the bug finding bonus challenge, take a look at this line of code:</p><div class="language-swift line-numbers-mode" data-ext="swift"><pre class="language-swift"><code>usedWords<span class="token punctuation">.</span><span class="token function">insert</span><span class="token punctuation">(</span>answer<span class="token punctuation">,</span> at<span class="token punctuation">:</span> <span class="token number">0</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Is that what it should be?</p>`,14),T={class:"hint-container info"},A=e("p",{class:"hint-container-title"},"Wrap up - Additional",-1),O={href:"https://hackingwithswift.com/review/hws/project-5-word-scramble",target:"_blank",rel:"noopener noreferrer"},C=e("p",null,"Once you’re done, tell other people: you’ve built your second game for iOS, and you’ve learned more about table views, alert controllers, and more.",-1),E=e("p",null,"You should be proud of what you’ve accomplished – keep going!",-1);function W(n,Y){const s=r("router-link"),a=r("ExternalLinkIcon"),u=r("YouTube");return c(),p("div",null,[e("h1",y,[w,t(" "+i(n.$frontmatter.title)+" 관련",1)]),e("blockquote",null,[e("p",null,i(n.$frontmatter.description),1)]),e("nav",m,[e("ul",null,[e("li",null,[o(s,{to:"#project-5-part-three"},{default:l(()=>[t("Project 5, part three")]),_:1}),e("ul",null,[e("li",null,[o(s,{to:"#wrap-up"},{default:l(()=>[t("Wrap up")]),_:1})])])])])]),f,e("details",b,[_,e("p",null,[e("a",v,[t("📎link"),o(a)])]),o(u,{id:"jxvEBafyo5A"}),k,j,I,x,e("p",null,[e("a",S,[t("Click here to review what you learned in project 5."),o(a)])]),B]),e("div",T,[A,e("ul",null,[e("li",null,[e("a",O,[t("Review for Project 5: Word Scramble"),o(a)])])])]),C,E])}const R=d(g,[["render",W],["__file","29.html.vue"]]);export{R as default};
